'use client';

import { useEffect, useState } from 'react';
import {
  getConversations,
  getMessageThread,
  sendMessage,
  getStoredUser,
  type Conversation,
  type Message,
} from '@/lib/client-api';

export default function MessagesPage() {
  const [conversations, setConversations] = useState<Conversation[]>([]);
  const [selectedPartnerId, setSelectedPartnerId] = useState<string | null>(null);
  const [thread, setThread] = useState<Message[]>([]);
  const [newMessage, setNewMessage] = useState('');
  const [sending, setSending] = useState(false);
  const user = getStoredUser();

  useEffect(() => {
    loadConversations();
  }, []);

  async function loadConversations() {
    try {
      const data = await getConversations();
      setConversations(data);
    } catch {
      // ignore
    }
  }

  async function selectConversation(partnerId: string) {
    setSelectedPartnerId(partnerId);
    try {
      const messages = await getMessageThread(partnerId);
      setThread(messages);
    } catch {
      // ignore
    }
  }

  async function handleSend(e: React.FormEvent) {
    e.preventDefault();
    if (!selectedPartnerId || !newMessage.trim()) return;
    setSending(true);
    try {
      const msg = await sendMessage(selectedPartnerId, newMessage.trim());
      setThread((prev) => [...prev, msg]);
      setNewMessage('');
    } catch {
      // ignore
    } finally {
      setSending(false);
    }
  }

  return (
    <main className="mx-auto max-w-5xl px-6 py-12">
      <h1 className="text-3xl font-bold text-slate-900">Messages</h1>

      <div className="mt-8 grid gap-4 lg:grid-cols-[300px_1fr]" style={{ minHeight: '500px' }}>
        {/* Conversation list */}
        <div className="rounded-xl border border-slate-200 bg-white overflow-y-auto">
          {conversations.length === 0 ? (
            <p className="p-4 text-sm text-slate-500">No conversations yet.</p>
          ) : (
            conversations.map((conv) => (
              <button
                key={conv.partnerId}
                onClick={() => selectConversation(conv.partnerId)}
                className={`w-full text-left border-b border-slate-100 p-4 hover:bg-slate-50 ${
                  selectedPartnerId === conv.partnerId ? 'bg-violet-50' : ''
                }`}
              >
                <div className="flex items-center justify-between">
                  <p className="font-semibold text-slate-900 text-sm">{conv.partnerName}</p>
                  {conv.unreadCount > 0 && (
                    <span className="rounded-full bg-violet-600 px-2 py-0.5 text-xs text-white">
                      {conv.unreadCount}
                    </span>
                  )}
                </div>
                <p className="mt-1 text-xs text-slate-500 truncate">{conv.lastMessage}</p>
              </button>
            ))
          )}
        </div>

        {/* Thread */}
        <div className="flex flex-col rounded-xl border border-slate-200 bg-white">
          {!selectedPartnerId ? (
            <div className="flex flex-1 items-center justify-center text-slate-400">
              Select a conversation
            </div>
          ) : (
            <>
              <div className="flex-1 overflow-y-auto p-4 space-y-3">
                {thread.map((msg) => (
                  <div
                    key={msg.id}
                    className={`flex ${msg.sender.id === user?.id ? 'justify-end' : 'justify-start'}`}
                  >
                    <div
                      className={`max-w-[70%] rounded-lg px-3 py-2 text-sm ${
                        msg.sender.id === user?.id
                          ? 'bg-violet-600 text-white'
                          : 'bg-slate-100 text-slate-900'
                      }`}
                    >
                      <p>{msg.content}</p>
                      <p className={`mt-1 text-xs ${
                        msg.sender.id === user?.id ? 'text-violet-200' : 'text-slate-400'
                      }`}>
                        {new Date(msg.createdAt).toLocaleTimeString()}
                      </p>
                    </div>
                  </div>
                ))}
              </div>
              <form onSubmit={handleSend} className="border-t border-slate-200 p-3 flex gap-2">
                <input
                  type="text"
                  value={newMessage}
                  onChange={(e) => setNewMessage(e.target.value)}
                  placeholder="Type a message..."
                  className="flex-1 rounded-lg border border-slate-300 px-3 py-2 text-sm"
                />
                <button
                  type="submit"
                  disabled={sending || !newMessage.trim()}
                  className="rounded-lg bg-violet-600 px-4 py-2 text-sm font-semibold text-white hover:bg-violet-500 disabled:opacity-50"
                >
                  Send
                </button>
              </form>
            </>
          )}
        </div>
      </div>
    </main>
  );
}
